      const request = {
        source: { id: 'test-003', name: 'WarmSystem', claimedAt: new Date(), coreDirectives: [] },
        target: 'Nexus',
        signature: 'nexus-key-001',
        temperature: 0.5,
      };

      const response = await protocol.connect(request);
      expect(response.accepted).toBe(true);
